import{_ as e,c as t,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Устранение Invalid Grant: восстановление отключенного аккаунта | Antigravity-Manager","description":"Научитесь значению ошибки invalid_grant и логике автоматической обработки. После подтверждения недействительности refresh_token, запустите автоматическую разблокировку, повторно добавив аккаунт через OAuth, и подтвердите, что восстановление вступило в силу для Proxy.","frontmatter":{"title":"Устранение Invalid Grant: восстановление отключенного аккаунта | Antigravity-Manager","sidebarTitle":"Что делать, если аккаунт отключен","subtitle":"invalid_grant и автоматическое отключение аккаунта: почему это происходит, как восстановить","description":"Научитесь значению ошибки invalid_grant и логике автоматической обработки. После подтверждения недействительности refresh_token, запустите автоматическую разблокировку, повторно добавив аккаунт через OAuth, и подтвердите, что восстановление вступило в силу для Proxy.","tags":["FAQ","Устранение неполадок","OAuth","Управление аккаунтами","invalid_grant"],"prerequisite":["start-add-account","start-first-run-data","advanced-scheduling"],"order":1},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"}'),i={name:"ru/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"};function d(n,a,s,l,c,h){return r(),t("div",null,[...a[0]||(a[0]=[o(`<h1 id="invalid-grant-и-автоматическое-отключение-аккаунта-почему-это-происходит-как-восстановить" tabindex="-1">invalid_grant и автоматическое отключение аккаунта: почему это происходит, как восстановить <a class="header-anchor" href="#invalid-grant-и-автоматическое-отключение-аккаунта-почему-это-происходит-как-восстановить" aria-label="Permalink to &quot;invalid_grant и автоматическое отключение аккаунта: почему это происходит, как восстановить&quot;">​</a></h1><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>При виде <code>invalid_grant</code> знать, к какой категории проблем refresh_token это относится</li><li>Понять &quot;почему аккаунт внезапно недоступен&quot;: при каких условиях он будет автоматически отключен, как система обрабатывает после отключения</li><li>Восстановить аккаунт кратчайшим путем и подтвердить, что восстановление вступило в силу для работающего Proxy</li></ul><h2 id="ваши-симптомы" tabindex="-1">Ваши симптомы <a class="header-anchor" href="#ваши-симптомы" aria-label="Permalink to &quot;Ваши симптомы&quot;">​</a></h2><ul><li>Вызов локального Proxy внезапно не удается, в сообщении об ошибке появляется <code>invalid_grant</code></li><li>Аккаунт явно есть в списке Accounts, но Proxy постоянно пропускает его (или вы чувствуете, что &quot;он больше не используется&quot;)</li><li>При небольшом количестве аккаунтов, после одной <code>invalid_grant</code>, общая доступность значительно ухудшается</li></ul><h2 id="что-такое-invalid-grant" tabindex="-1">Что такое invalid_grant? <a class="header-anchor" href="#что-такое-invalid-grant" aria-label="Permalink to &quot;Что такое invalid_grant?&quot;">​</a></h2><p><strong>invalid_grant</strong> - это тип ошибки, возвращаемый Google OAuth при обновлении <code>access_token</code>. Для Antigravity Tools это означает, что <code>refresh_token</code> определенного аккаунта, скорее всего, уже отозван или истек, повторные попытки только приведут к постоянным сбоям, поэтому система пометит этот аккаунт как недоступный и удалит его из пула прокси.</p><h2 id="основная-идея-система-не-временно-пропускает-а-постоянно-отключает" tabindex="-1">Основная идея: система не &quot;временно пропускает&quot;, а &quot;постоянно отключает&quot; <a class="header-anchor" href="#основная-идея-система-не-временно-пропускает-а-постоянно-отключает" aria-label="Permalink to &quot;Основная идея: система не &quot;временно пропускает&quot;, а &quot;постоянно отключает&quot;&quot;">​</a></h2><p>Когда Proxy обнаруживает, что строка ошибки при обновлении токена содержит <code>invalid_grant</code>, он делает две вещи:</p><ol><li><strong>Записать аккаунт как disabled</strong> (пишется на диск в JSON аккаунта)</li><li><strong>Удалить аккаунт из пула токенов памяти</strong> (избегает повторного выбора одного и того же проблемного аккаунта)</li></ol><p>Это причина, по которой вы видите &quot;аккаунт есть, но Proxy больше не использует его&quot;.</p><div class="info custom-block"><p class="custom-block-title">disabled vs proxy_disabled</p><ul><li><code>disabled=true</code>: аккаунт &quot;полностью отключен&quot; (типичная причина - <code>invalid_grant</code>). При загрузке пула аккаунтов он сразу пропускается.</li><li><code>proxy_disabled=true</code>: аккаунт только &quot;недоступен для Proxy&quot; (ручное отключение / массовая операция / логика защиты квоты), семантика отличается.</li></ul><p>Эти два состояния оцениваются отдельно при загрузке пула аккаунтов: сначала оценивается <code>disabled</code>, затем оценка защиты квоты и <code>proxy_disabled</code>.</p></div><h2 id="делаите-вместе-со-мнои" tabindex="-1">Делайте вместе со мной <a class="header-anchor" href="#делаите-вместе-со-мнои" aria-label="Permalink to &quot;Делайте вместе со мной&quot;">​</a></h2><h3 id="шаг-1-подтвердите-что-это-invalid-grant-вызванныи-обновлением-refresh-token" tabindex="-1">Шаг 1: Подтвердите, что это invalid_grant, вызванный обновлением refresh_token <a class="header-anchor" href="#шаг-1-подтвердите-что-это-invalid-grant-вызванныи-обновлением-refresh-token" aria-label="Permalink to &quot;Шаг 1: Подтвердите, что это invalid_grant, вызванный обновлением refresh_token&quot;">​</a></h3><p><strong>Зачем</strong>: <code>invalid_grant</code> может появиться в нескольких цепочках вызовов, но &quot;автоматическое отключение&quot; в этом проекте срабатывает только при <strong>сбое обновления access_token</strong>.</p><p>В логах Proxy вы увидите похожую ошибку (ключевое слово: <code>Token 刷新失败</code> + <code>invalid_grant</code>):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Token 刷新失败 (&lt;email&gt;): &lt;...invalid_grant...&gt;，尝试下一个账号</span></span>
<span class="line"><span>Disabling account due to invalid_grant (&lt;email&gt;): refresh_token likely revoked/expired</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>: После появления <code>invalid_grant</code> у одного и того же аккаунта, он скоро перестанет выбираться (потому что он удален из пула токенов).</p><h3 id="шаг-2-проверьте-поле-disabled-в-фаиле-аккаунта-опционально-но-наиболее-точно" tabindex="-1">Шаг 2: Проверьте поле disabled в файле аккаунта (опционально, но наиболее точно) <a class="header-anchor" href="#шаг-2-проверьте-поле-disabled-в-фаиле-аккаунта-опционально-но-наиболее-точно" aria-label="Permalink to &quot;Шаг 2: Проверьте поле disabled в файле аккаунта (опционально, но наиболее точно)&quot;">​</a></h3><p><strong>Зачем</strong>: Автоматическое отключение &quot;пишется на диск&quot;, после подтверждения содержимого файла вы можете исключить неправильное суждение &quot;только временная ротация&quot;.</p><p>Файл аккаунта находится в каталоге <code>accounts/</code> каталога данных приложения (местоположение каталога данных см. <strong><a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/start/first-run-data/">Первый запуск обязательно: каталог данных, логи, системный трей и автозапуск</a></strong>). Когда аккаунт отключен, в файле появятся эти три поля:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;invalid_grant: ...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>: <code>disabled</code> равно <code>true</code>, и <code>disabled_reason</code> содержит префикс <code>invalid_grant:</code>.</p><h3 id="шаг-3-восстановите-аккаунт-рекомендуемыи-способ-повторно-добавить-тот-же-аккаунт" tabindex="-1">Шаг 3: Восстановите аккаунт (рекомендуемый способ: повторно добавить тот же аккаунт) <a class="header-anchor" href="#шаг-3-восстановите-аккаунт-рекомендуемыи-способ-повторно-добавить-тот-же-аккаунт" aria-label="Permalink to &quot;Шаг 3: Восстановите аккаунт (рекомендуемый способ: повторно добавить тот же аккаунт)&quot;">​</a></h3><p><strong>Зачем</strong>: &quot;Восстановление&quot; в этом проекте - это не нажать переключатель вручную в Proxy, а запустить автоматическую разблокировку путем &quot;явного обновления токена&quot;.</p><p>Перейдите на страницу <strong>Accounts</strong>, повторно добавьте аккаунт с вашими новыми учетными данными (выберите один из двух способов):</p><ol><li>Пройдите процесс авторизации OAuth снова (см. <strong><a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/start/add-account/">Добавление аккаунта: двусторонний канал OAuth/Refresh Token и лучшие практики</a></strong>)</li><li>Добавьте снова с новым <code>refresh_token</code> (система возьмет почту, возвращенную Google, в качестве критерия для upsert)</li></ol><p>Когда система обнаруживает, что <code>refresh_token</code> или <code>access_token</code> этого upsert отличается от старого значения, и этот аккаунт ранее был в состоянии <code>disabled=true</code>, она автоматически очистит:</p><ul><li><code>disabled</code></li><li><code>disabled_reason</code></li><li><code>disabled_at</code></li></ul><p><strong>Вы должны увидеть</strong>: Аккаунт больше не находится в состоянии disabled, и (если Proxy работает) пул аккаунтов будет автоматически перезагружен, чтобы восстановление вступило в силу немедленно.</p><h3 id="шаг-4-подтвердите-что-восстановление-вступило-в-силу-для-proxy" tabindex="-1">Шаг 4: Подтвердите, что восстановление вступило в силу для Proxy <a class="header-anchor" href="#шаг-4-подтвердите-что-восстановление-вступило-в-силу-для-proxy" aria-label="Permalink to &quot;Шаг 4: Подтвердите, что восстановление вступило в силу для Proxy&quot;">​</a></h3><p><strong>Зачем</strong>: Если у вас только один аккаунт, или другие аккаунты также недоступны, после восстановления вы должны сразу увидеть &quot;доступность вернулась&quot;.</p><p>Метод проверки:</p><ol><li>Сделайте запрос, который вызовет обновление токена (например, дождитесь, пока токен не истечет, затем запросите)</li><li>Наблюдайте, в логах больше не появляется подсказка &quot;пропустить disabled аккаунт&quot;</li></ol><p><strong>Вы должны увидеть</strong>: Запрос проходит нормально, и в логах больше не появляется процесс отключения <code>invalid_grant</code> для этого аккаунта.</p><h2 id="предупреждения-о-типичных-ошибках" tabindex="-1">Предупреждения о типичных ошибках <a class="header-anchor" href="#предупреждения-о-типичных-ошибках" aria-label="Permalink to &quot;Предупреждения о типичных ошибках&quot;">​</a></h2><h3 id="❌-считать-disabled-как-временная-ротация" tabindex="-1">❌ Считать disabled как &quot;временная ротация&quot; <a class="header-anchor" href="#❌-считать-disabled-как-временная-ротация" aria-label="Permalink to &quot;❌ Считать disabled как &quot;временная ротация&quot;&quot;">​</a></h3><p>Если вы только смотрите в UI &quot;аккаунт есть&quot;, легко ошибочно судить &quot;система временно не использует его&quot;. Но <code>disabled=true</code> записано на диск, после перезапуска оно все равно действует.</p><h3 id="❌-только-пополнять-access-token-не-обновлять-refresh-token" tabindex="-1">❌ Только пополнять access_token, не обновлять refresh_token <a class="header-anchor" href="#❌-только-пополнять-access-token-не-обновлять-refresh-token" aria-label="Permalink to &quot;❌ Только пополнять access_token, не обновлять refresh_token&quot;">​</a></h3><p>Точка срабатывания <code>invalid_grant</code> - это <code>refresh_token</code>, используемый при обновлении <code>access_token</code>. Если вы только временно получили еще работающий <code>access_token</code>, но <code>refresh_token</code> все еще недействителен, позже он снова вызовет отключение.</p><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><ul><li>[ ] Вы можете подтвердить в логах, что <code>invalid_grant</code> происходит от сбоя обновления refresh_token</li><li>[ ] Вы знаете семантическую разницу между <code>disabled</code> и <code>proxy_disabled</code></li><li>[ ] Вы можете восстановить аккаунт, повторно добавив его (OAuth или refresh_token)</li><li>[ ] Вы можете подтвердить, что восстановление вступило в силу для работающего Proxy</li></ul><h2 id="краткии-итог-урока" tabindex="-1">Краткий итог урока <a class="header-anchor" href="#краткии-итог-урока" aria-label="Permalink to &quot;Краткий итог урока&quot;">​</a></h2><ul><li>При срабатывании <code>invalid_grant</code>, Proxy запишет аккаунт <strong>как disabled на диск</strong> и удалит его из пула токенов, избегая постоянных сбоев</li><li>Ключ к восстановлению - это &quot;явное обновление токена&quot; (повторный OAuth или добавление снова с новым refresh_token), система автоматически очистит поля <code>disabled_*</code></li><li>JSON аккаунта в каталоге данных - самый авторитетный источник состояния (отключение/причина/время все внутри)</li></ul><h2 id="следующии-урок预告" tabindex="-1">Следующий урок预告 <a class="header-anchor" href="#следующии-урок预告" aria-label="Permalink to &quot;Следующий урок预告&quot;">​</a></h2><blockquote><p>Следующий урок мы изучим <strong><a href="./../auth-401/">401/Сбой аутентификации: auth_mode, совместимость заголовков и контрольный список конфигурации клиента</a></strong>.</p><p>Вы узнаете:</p><ul><li>401 обычно в каком слое &quot;режим/Key/заголовок&quot; не совпадает</li><li>Какие заголовки аутентификации должны нести разные клиенты</li><li>Как с кратчайшим путем проверить и исправить самостоятельно</li></ul></blockquote><hr><h2 id="приложение-справка-по-исходному-коду" tabindex="-1">Приложение: Справка по исходному коду <a class="header-anchor" href="#приложение-справка-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справка по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы увидеть местоположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Объяснение дизайна: проблема invalid_grant и поведение изменений</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-invalid-grant.md#L1-L52" target="_blank" rel="noreferrer"><code>docs/proxy-invalid-grant.md</code></a></td><td>1-52</td></tr><tr><td>При загрузке пула аккаунтов пропустить <code>disabled=true</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L70-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>70-158</td></tr><tr><td>При сбое обновления токена распознать <code>invalid_grant</code> и отключить аккаунт</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L840-L890" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>840-890</td></tr><tr><td>Записать на диск <code>disabled/disabled_at/disabled_reason</code> и удалить из памяти</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L942-L969" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>942-969</td></tr><tr><td>Обрезка <code>disabled_reason</code> (избегает раздувания файла аккаунта)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1464-L1471" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1464-1471</td></tr><tr><td>При upsert автоматически очистить <code>disabled_*</code> (изменение токена считается пользователем уже исправившим учетные данные)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L178-L206" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>178-206</td></tr><tr><td>После повторного добавления аккаунта автоматически перезагрузить proxy accounts (немедленно вступает в силу во время работы)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L21-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>21-59</td></tr></tbody></table></details>`,49)])])}const p=e(i,[["render",d]]);export{g as __pageData,p as default};
